import{_ as s,C as t,o as h,c,j as e,a as o,E as i,a3 as p}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第29章 江海","description":"帛书德篇第29章 · 江海（通行本第66章）","frontmatter":{"title":"帛书第29章 江海","description":"帛书德篇第29章 · 江海（通行本第66章）","category":"guide","aliases":["帛书第29章","马王堆老子29","通行本第66章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-29.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-29.md","lastUpdated":1778775693000}'),m={name:"daoism/texts/dao-de-jing-boshu/chapter-29.md"};function u(x,a,b,_,g,f){const n=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),c("div",null,[a[0]||(a[0]=e("h1",{id:"帛书老子第29章",tabindex:"-1"},[o("帛书老子第29章 "),e("a",{class:"header-anchor",href:"#帛书老子第29章","aria-label":'Permalink to "帛书老子第29章"'},"​")],-1)),i(n,{title:"第29章 江海",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第66章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第29章"},{label:"对照",text:"通行本第66章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["江海所以能为百浴王者","以亓善下之 是以能为百浴王","是以圣人之欲上民也 必以亓言下之","欲先民也 必以亓身后之","故居前而民弗害也 居上而民弗重也","天下乐推而弗猒也 非以亓无诤与","故天下莫能与诤"]}),i(l,{lines:[{text:"江海所以能为百浴王者 以亓善下之 是以能为百浴王",tone:"起",guide:"江海之所以能成为一切溪谷（浴通谷）的王者，是因为它善于处在最低下之处——处下而能容纳百川。"},{text:"是以圣人之欲上民也 必以亓言下之 欲先民也 必以亓身后之",tone:"法",guide:"所以圣人要想居于人民之上，必须用言辞表示谦下；要想居于人民之先，必须把自身放在后面——以退为进。"},{text:"故居前而民弗害也 居上而民弗重也",tone:"理",guide:"所以站在前面人民不觉得有害，居于上位人民不觉得沉重——因为他不争夺、不强压。"},{text:"天下乐推而弗猒也 非以亓无诤与 故天下莫能与诤",tone:"收",guide:"天下人乐于推举他而不厌倦（猒通厌），不正是因为他不争吗（诤通争）——所以天下没有人能和他争。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[o("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(d,{items:[{term:"浴",pinyin:["gǔ"],meaning:"通「谷」——溪谷。百浴王即百谷之王。",context:"帛书以浴为谷，全书通用。"},{term:"猒",pinyin:["yàn"],meaning:"通「厌」——厌倦。天下乐推而弗猒——天下人推举他而不厌倦。",context:"帛书用猒为厌。"},{term:"诤",pinyin:["zhèng"],meaning:"通「争」——竞争、争夺。非以亓无诤与——不正是因为他没有争吗。",context:"帛书以诤为争。"}]}),a[3]||(a[3]=p('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「江海」，帛书此章围绕「百浴王善下」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第66章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(m,[["render",u]]);export{q as __pageData,k as default};
